import{_ as p}from"./nyalra_kb-7135827b.js";import{_ as r}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as d,Y as i,Z as e,$ as t,a1 as a,a2 as _,a0 as m,C as o}from"./framework-91490e6a.js";const f={},g=e("figure",null,[e("img",{src:p,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),b=e("p",null,"没想到已经到倒数第二回了，下一回就是最终回了。",-1),h={href:"https://tree-novel.com/works/episode/9172da8cfdafe31dde9d23d170bbab5b.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),u=m('<hr><p>这周第一次去了国外……也就是说，这篇文章是在返回的飞机上写的，实际上我只是在手机的备忘录里敲击着文字而已。毕竟开启了飞行模式，所以正好有些空闲时间。</p><p>那么，在这个连载中不会涉及海外的活动（译者注：WePlay文化展）相关的内容，我大胆地跳过这部分。如果你感兴趣的话，可以详阅我的账号。现在，让我谈谈在海外所感受到的一些事情。</p><p>首先，旅行海外的难度主要取决于「语言的差异」。在第一天，我独自一人走在街上，与城市的居民无法进行有效的交流。从耳朵里传来的信息几乎毫无用处。与之相对的是，在第二天及以后有了翻译，一切都变得安心了。尽管由于文化差异而存在一些常识上的差异，但只要语言能够沟通，就可以解决大部分问题。</p><p>换句话说，人类通过语言共享意图和常识，建立「前提」以获得安心感。首先，通过交换问候，可以建立「没有敌意」的前提，接着通过自我介绍共享自己的身份和立场，让对方理解。这样的对话在潜意识中反复进行，不断积累信任。如果语言无法沟通，这个重要的前提就会崩溃，人会深陷于不安之中。</p><p>反过来说，即使在国内，也许有意识地考虑这个「前提」并进行交流是个不错的主意。</p><p>「这个人应该不会突然发火」，「他可能会对这样的话题感兴趣」，相互确认这些。在初次见面的情况下，顺利地进行这些共享是很好的。对于作家来说，有代表作品会让事情变得轻松很多。像「我是制作/喜爱这样的作品的人」这样的信息可以瞬间共享形象，有点像名片一样。</p><p>相反地，提前分享「我在这种情况下比较脆弱，希望能够避免」的信息也是很方便的。因为对方可能无法看到敏感的部分，或者不了解哪些是不能触及的，因此及早勇敢地申告这些事项是重要的。比如，「我绝对会睡过头，所以早上见面是不可能的」等。一旦这个前提被共享和理解，就可以在已经制定的规则内进行调整。与游戏中的禁卡不同，如果规则已经设定，抱怨「为什么不能用！」也是毫无意义的。在现实里，规则一旦设定，也可以在其内进行调整。</p><p>与朋友相处多年，有的甚至超过10年，各种「前提」都已经积累，因此感到安心。「他会因为去看这部电影而高兴」、「他应该不会因为帮助这么多而生气」、「一定程度的吐槽应该是可以接受的」等。因为我们是人类，所以偶尔可能会打破默契而发生争吵。但由于我们了解彼此的优点和缺点，所以更容易相处。用更正式的说法，这建立了信任。</p><p>沟通的基本可能是提供「安心」。在不了解对方是谁的情况下，透露最基本的常识，比如学历和职业经历，是很明显的做法。进入一所好大学、就职于大公司，通常可以相对轻松地获得初次见面的信任。当然，这只是一般情况。通过将这些信息制作成名片进行交流，可以衡量彼此的常识水平。这就是社会交往。</p><p>有些人可能会认为拥有这种社会常识反而是一种累赘，因此选择远离。嗯，我也尽量避免与正常人交往。因为无法共享「前提」。当谈到像「能够准时起床」、「不会错过火车」、「能够及时发送发票」等常识时，如果不能满足这些前提，就需要解释自己有多么麻烦。为了避免在关键时刻发生问题，所以如果规则不同，我有时会悄悄离开。</p><p>从一开始的话题偏离了预期的方向，就像现在乘坐的飞机一样，飞向了意料之外的地方。</p><p>写完了，等我到达机场就会连接网络，然后编辑这篇稿件发出。稿件定于0点发布，但实际上在21时才发送。非常抱歉……不过，实际上编辑也曾多次忘记更新这个专栏而延误。我们之间有一个共识：「在不行的时候就别勉强，尽量在能力范围内随意一些」，所以在这方面我们放得比较开！嗯，我就随便一点地展现出这种心态！真的非常抱歉。从下周开始，我会更加从容地提交……。</p><p><em>（※担当私信：抱歉。一直以来谢谢你了。）</em></p><hr><p><img src="'+r+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/f15fb32d5df2cca2f5aa4fbe94d996d7.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/bb20de08ac94ff7ddb607e675008471f.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/12d60895369389adccd10fc8eeaeb62f.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/fa5d424d2e0ab24c410ac0fbae8b1271.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【METAL BUILD サーバイン】这是在『機動戦士ガンダム 逆襲のシャア』中出现的稀有机体。最近在超级机器人大战游戏中的登场次数增加，因此知名度可能也提高了。坦白说，在原作中几乎不进行任何动作，因此这次立体物的大部分姿势都是粉丝的愿望：「希望它能这样动。」但是，设计过于精致，简直就像宝石一样。</p></blockquote>',17);function y(v,x){const l=o("ExternalLinkIcon"),n=o("RouterLink");return s(),d("div",null,[i(" more "),g,b,e("p",null,[t("原文链接："),e("a",h,[t("第53回／前提の共有"),a(l)])]),e("blockquote",null,[k,e("p",null,[a(n,{to:"/posts/Translate/nyalra_kb_52.html"},{default:_(()=>[t("【奈亚拉面壁自语】第52回｜信息碎片【231114】")]),_:1})])]),u])}const V=c(f,[["render",y],["__file","nyalra_kb_53.html.vue"]]);export{V as default};
